//! The RAW IN-MEMORY frame source feeds the EXACT same vision entry as the mp4 decode path.
//!
//! Phase 5b drops the mp4 round-trip from the self-vision loop: a renderer's packed RGB24 frames
//! go straight into third-eye via `frffmpeg::decode::RawFrameSource` instead of being encoded to an
//! mp4 and re-decoded by ffmpeg. This test proves the SOURCE is the only thing that changed — the
//! `Frame` it yields is byte-identical to a directly-built `Frame`, and feeding those frames through
//! `vision::detect` produces the identical proposals. No ffmpeg in this test (no mp4 hop): the
//! frames the ffmpeg `Decoder` would yield ARE these exact RGB24 bytes (rawvideo rgb24 is a verbatim
//! copy of the pixels), so the raw-source path and the decode path see the same `detect` input.

use frffmpeg::decode::{Frame, RawFrameSource};
use third_eye::vision::{BackgroundModel, VisionConfig, detect};

const W: u32 = 160;
const H: u32 = 120;

/// Build a synthetic RGB24 frame: black field with one bright square blob moved by `(dx, dy)`.
/// This is the same shape a rendered frame has (a bright body on a dark sky), so `detect` finds it.
fn synth_rgb(dx: i32, dy: i32) -> Vec<u8> {
    let (w, h) = (W as i32, H as i32);
    let mut rgb = vec![0u8; (W * H * 3) as usize];
    let (bx, by, half) = (w / 2 + dx, h / 2 + dy, 16i32);
    for y in (by - half).max(0)..(by + half).min(h) {
        for x in (bx - half).max(0)..(bx + half).min(w) {
            let i = ((y * w + x) * 3) as usize;
            rgb[i] = 230;
            rgb[i + 1] = 240;
            rgb[i + 2] = 90;
        }
    }
    rgb
}

/// Feed a sequence of RGB24 buffers through `detect` and collect, per frame, the proposal count and
/// each proposal's rounded centroid — a content-level fingerprint of the vision entry's output.
fn detect_fingerprint(frames: &[Frame]) -> Vec<(usize, Vec<(i32, i32)>)> {
    let mut bg = BackgroundModel::new();
    // Static-camera config (the self-vision harness runs `--static-cam`): a single moving blob on a
    // fixed black field would otherwise be read as a global pan and suppressed.
    let mut cfg = VisionConfig::default();
    cfg.compensate = false;
    let mut out = Vec::new();
    for f in frames {
        // The perception core consumes the target-agnostic `third_eye::frame::Frame`; the native
        // decode/raw-source path yields `frffmpeg::decode::Frame`. The `From` bridge is a move of
        // the rgb buffer (no pixel copy) — same bytes, same `detect` input.
        let core_frame: third_eye::frame::Frame = f.clone().into();
        let (props, _fg) = detect(&core_frame, &mut bg, &cfg);
        let mut centroids: Vec<(i32, i32)> = props
            .iter()
            .map(|p| (p.cx.round() as i32, p.cy.round() as i32))
            .collect();
        centroids.sort_unstable();
        out.push((props.len(), centroids));
    }
    out
}

#[test]
fn raw_source_feeds_same_vision_entry_as_decode_path() {
    let fps = 24.0;
    // A translating-blob clip long enough to pass the background warm-up (default 8 frames) so the
    // vision entry actually fires: the exact RGB24 bytes a rawvideo decode would hand third-eye.
    let bufs: Vec<Vec<u8>> = (0..16).map(|i| synth_rgb(-40 + i * 5, 0)).collect();

    // (A) DECODE-PATH reference: frames as the ffmpeg `Decoder` would construct them (verbatim
    //     RGB24 bytes, pts reconstructed from fps). detect() over these is the file-round-trip read.
    let decode_frames: Vec<Frame> = bufs
        .iter()
        .enumerate()
        .map(|(i, b)| Frame {
            index: i as u64,
            pts_s: i as f64 / fps,
            width: W,
            height: H,
            rgb: b.clone(),
        })
        .collect();

    // (B) RAW IN-MEMORY path: concatenate the same bytes onto a single stream and read them back
    //     through RawFrameSource (the in-memory transport — stdin in the binary, a slice here).
    let mut stream = Vec::new();
    for b in &bufs {
        stream.extend_from_slice(b);
    }
    let raw_frames: Vec<Frame> = RawFrameSource::new(&stream[..], W, H, fps, None)
        .unwrap()
        .map(|f| f.unwrap())
        .collect();

    // The Frame the raw source yields is byte-identical to the decode-path Frame: same index, dims,
    // reconstructed pts, and pixels. This is the "same Frame the video path produces" guarantee.
    assert_eq!(raw_frames.len(), decode_frames.len());
    for (r, d) in raw_frames.iter().zip(&decode_frames) {
        assert_eq!(r.index, d.index);
        assert_eq!((r.width, r.height), (d.width, d.height));
        assert!((r.pts_s - d.pts_s).abs() < 1e-12);
        assert_eq!(r.rgb, d.rgb, "raw RGB24 == decode RGB24 (no mp4 hop, no re-encode)");
    }

    // And the vision entry over the raw frames yields the IDENTICAL proposals as over the decode
    // frames: same perception, tighter transport (the Phase-5b claim).
    let raw_fp = detect_fingerprint(&raw_frames);
    let decode_fp = detect_fingerprint(&decode_frames);
    assert_eq!(
        raw_fp, decode_fp,
        "raw-source vision output must match the decode-path vision output frame-for-frame"
    );

    // Sanity: the clip is non-trivial — the blob was actually detected on at least one frame, so
    // the equality above is over a real perception, not two empty reads.
    assert!(
        raw_fp.iter().any(|(n, _)| *n > 0),
        "the synthetic translating blob should be detected (else the parity is vacuous)"
    );
}
